    /**
     * Fonction : MAJConj
     *      forme verbale ::= [augment] + thème verbal + [suffixe de mode] + terminaison
     *      thème verbal ::= [redoublement] + radical + [suffixe de thème] + [voyelle thématique]
     * Fction appelante : Conjugueur.Vue.JFrameConjugGrecA::JFrameConjugGrecA
     * Algorithme : 
     * 1. Remettre le tableau de conjugaison à zéro
     * 2. S'aiguiller selon le temps
     * 2.1 Voix active
     * 2.1.1 S'aiguiller selon 
     * 2.1.1.1 Thèmes Passé
     * 2.1.1.2 Thèmes Inaccompli
     * 2.1.1.2.1 Si le verbe est régulier alors
     * 2.1.1.2.1.1  Créer une ligne pour chaque déclinaison et y placer les libellés des personnes à conjuguer : masc sing, masc plur, fém sing, fém plur en appelant la fction "AjouterPersonnes ])"
     * 2.1.1.2.1.2 S'il n'y a pas de présent particuler alors
     * 2.1.1.2.1.2.1 Pour ts les caractères de l'infinitif faire
     * 2.1.1.2.1.2.1.1 Si c'est une consonne alors
     * 2.1.1.2.1.2.1.1.1 Incrémenter compteur de consonnes
     * 2.1.1.2.1.2.1.1.2 Insérer un "וֹ" en 2è position s'il n'est pas déjà présent
     * 2.1.1.2.1.2.1.1.3 Copier le caractère en appelant "CopierCaractèRacine"
     * 2.3 Groupe Piel
    * 2.3.1 S'aiguiller selon le temps       
     * 2.3.1 Thèmes Passé
     * 2.3.2 Thèmes Inaccompli
     * 2.3.2.1  Créer une ligne pour chaque déclinaison et y placer les libellés des personnes à conjuguer : masc sing, masc plur, fém sing, fém plur en appelant la fction "AjouterPersonnes ()"
     * 2.7 Groupe Piel
    * 2.7.1 S'aiguiller selon le temps       
     * 2.7.1 Thèmes Passé
     * 2.7.2 Thèmes Inaccompli
     * 2.7.2.1  Créer une ligne pour chaque déclinaison et y placer les libellés des personnes à conjuguer : masc sing, masc plur, fém sing, fém plur en appelant la fction "AjouterPersonnes ()"
     */
    @Override
    public void MAJConj(Conjugueur.C.Conjug contrôleur) {
        if (DEBUG) { System.out.println ("Conjugueur.M.ConjTableGrecA::MAJConj, Verbe = " + Conjugueur.M.ConjugGrecA.cbVerbeM.get(contrôleur.model.getIndVerbe()).getAttributeValue(Conjugueur.M.ConjugGrecA.ATTRIBUT)+", Mode = "+contrôleur.model.getMode()+ ", théme = " + Conjugueur.M.ConjugGrecA.GAT.i2T(contrôleur.model.getThème()).toString()) ;   }
        try {
            vider() ;
            switch (Conjugueur.M.ConjugGrecA.GAM.i2M(contrôleur.model.getMode())) {                                          // mode
                case Indicatif, Subjonctif, Optatif -> {                                             // indicatif
                    déclinaisonChildren = Conjugueur.M.ConjugGrecA.cbVerbeM.get(contrôleur.model.getIndVerbe()).getChildren("déclinaison");
                    switch (Conjugueur.M.ConjugGrecA.GAT.i2T(contrôleur.model.getThème())) {
                        case Imperfectif, Futur, Aoriste, Parfait -> {                                       // temps présent
                            for (GAP personne : GAP.values()) {
                                if (déclinaisonChildren.isEmpty()) {                    // verbe régulier
                                    DéclinerRégulièrement (personne, contrôleur) ;    
                                }                                                       // verbe régulier
                                else CopierIrrégularités (personne, contrôleur) ;
                                AjouterTranslittération(inbLignes, graToLatinTrans) ;
                            }                                           // ttes les personnes
                        }                                                           // temps présent
                    }
                // temps
                // switch (ConjModeGrecAM.getMode())
                }                                                               // indicatif
                case Impératif -> {
                    déclinaisonChildren = Conjugueur.M.ConjugGrecA.cbVerbeM.get(contrôleur.model.getIndVerbe()).getChildren("déclinaison");
                    switch (Conjugueur.M.ConjugGrecA.GAT.i2T(contrôleur.model.getThème())) {
                        case Imperfectif -> {                                       // temps présent
                            for (GAP personne : GAP.values()) {
                                if((personne == GAP.GA1S)||(personne == GAP.GA1P)) continue ;
                                if (déclinaisonChildren.isEmpty()) {                    // verbe régulier
                                    DéclinerRégulièrement (personne, contrôleur) ;    
                                }                                                       // verbe régulier
                                else CopierIrrégularités (personne, contrôleur) ;
                            }                                           // ttes les personnes
                            AjouterTranslittération(inbLignes, graToLatinTrans) ;
                        }                                                           // temps présent
                    
                    }
                }                                                               // mode impératif
                case Infinitif -> {
                }                                                               // mode Infinitif
                case Participe -> {
                    switch (Conjugueur.M.ConjugGrecA.GAT.i2T(contrôleur.model.getThème())) {
                        case Imperfectif -> {
                            inbLignes = AjouterLigne(GAP.GA2S.ip(), "", JFrameConjugGrecA.LATIN, StyleConstants.ALIGN_RIGHT) ;
                            for (char c : (Conjugueur.M.ConjugGrecA.cbVerbeM.get(contrôleur.model.getIndVerbe()).getAttributeValue(Conjugueur.M.ConjugGrecA.ATTRIBUT)).substring(0, Conjugueur.M.ConjugGrecA.cbVerbeM.get(contrôleur.model.getIndVerbe()).getAttributeValue(Conjugueur.M.ConjugGrecA.ATTRIBUT).length()- 3).toCharArray()){
                                Copier (inbLignes, String.valueOf(c), DéclinaisonStyledDoc.stylera) ;
                            }                                                    // pour ts les caractères
                            if (!GAP.GA2S.spip(contrôleur.model.getMode(), contrôleur.model.getThème(), contrôleur.model.getVoix(), ConjugGrecA.itype.id()).isEmpty())
                                Suffixer (inbLignes, GAP.GA2S.spip(contrôleur.model.getMode(), contrôleur.model.getThème(), contrôleur.model.getVoix(), ConjugGrecA.itype.id())) ;
                        }
                        case Parfait -> {
                            inbLignes = AjouterLigne(GAP.GA2S.ip(), GAP.GA2S.lp(), LATIN, StyleConstants.ALIGN_RIGHT) ;
                            switch (Conjugueur.M.ConjugGrecA.cbVerbeM.get(contrôleur.model.getIndVerbe()).getAttributeValue(Conjugueur.M.ConjugGrecA.ATTRIBUT).substring(Conjugueur.M.ConjugGrecA.cbVerbeM.get(contrôleur.model.getIndVerbe()).getAttributeValue(Conjugueur.M.ConjugGrecA.ATTRIBUT).length() - 3)) {
                                case "are":
                                    break;                                      // 1er groupe
                            }                                                   // groupe
                            break;                                                   // temps parfait
                        }
                    } // temps
                }                                                               // mode participe
            }                                                                   // mode
        } catch (BadLocationException ble) {        }
    }                                                                           // updateTextPaneConj
        /**
     * Fonction : Substitue les conjugaisons régulières par irrégularités trouvées ds le xml
     * Algorithme : 
     * 1. Pour ttes irrégularités trouvées ds le xml faire
     * 1.1 Si cette irrégularité correspond au mode et au temps choisi alors
     * 1.1.1 Pour ttes les conjugaisons régulières déjà ds "tabLigneConj" faire
     * 1.1.1.1 Si la personne régulière se trouve être en même temps irrégulière alors
     * 1.1.1.1.1 si les conjugaisons diffèrent faire
     * 1.1.1.1.1.1 Supprimer de "tabLigneConj" la déclinaison régulière
     * 1.1.1.1.1.2 Insertion de l'irrégularité
     * 1.1.1.2 sinon
     * 1.1.1.2.1 Ajouter l'irrégularité
    */
    private void CopierIrrégularités (GAP personne, Conjugueur.C.Conjug contrôleur) throws BadLocationException {
        if (DEBUG) System.out.println("Conjugueur.M.ConjTableGrecA::CopierIrrégularités, mode = "+ contrôleur.model.getMode()+", théme = "+ Conjugueur.M.ConjugGrecA.GAT.i2T(contrôleur.model.getThème()).toString()) ;
        for (int i = 0; i < déclinaisonChildren.size(); i++) {                  // Pour ttes les déclinaisons
            if (   (déclinaisonChildren.get(i).getAttribute("mode").getValue().compareTo(Conjugueur.M.ConjugGrecA.GAM.i2M(contrôleur.model.getMode()).toString()) == 0)
                && (déclinaisonChildren.get(i).getAttribute("thème").getValue().compareTo(Conjugueur.M.ConjugGrecA.GAT.i2T(contrôleur.model.getThème()).toString()) == 0)
                && (déclinaisonChildren.get(i).getAttribute("personne").getValue().compareTo(personne.lp()) == 0)) {
                inbLignes = AjouterLigne(GAP.findByName(déclinaisonChildren.get(i).getAttribute("personne").getValue()).ip(), GAP.findByName(déclinaisonChildren.get(i).getAttribute("personne").getValue()).lp(), LATIN, StyleConstants.ALIGN_RIGHT) ;
                Copier(inbLignes, GAP.findByName(déclinaisonChildren.get(i).getAttribute("personne").getValue()).lip(), DéclinaisonStyledDoc.stylepp); Espace(inbLignes);
                Copier(inbLignes, déclinaisonChildren.get(i).getText(), DéclinaisonStyledDoc.stylesu);
            } 
        }                                                                       // Pour ttes les déclinaisons
    }                                                                           // CopierIrrégularités

    /**
     * @param itype indice de groupe 1, 2 ou 3
    * Algorithme
    * 1. Copier le libellé du Pronom Personnel
    * 2. Si le préfixe existe, l'ajouter
    */
    private void DéclinerRégulièrement(GAP personne, Conjugueur.C.Conjug contrôleur) throws BadLocationException {
        if (DEBUG) System.out.println("Conjugueur.M.ConjTableGrecA::DéclinerRégulièrement, personne = " + personne.lp+", Mode = "+contrôleur.model.getMode()+ /*", ConjThèmeM.getThème() = "+ConjThèmeM.getThème()+*/", Voix = "+Conjugueur.M.ConjugGrecA.V.i2V(contrôleur.model.getVoix()).toString()) ;
        inbLignes = AjouterLigne(personne.ip(), personne.lp(), JFrameConjugGrecA.LATIN, StyleConstants.ALIGN_RIGHT) ;
        Copier(personne.lip(), DéclinaisonStyledDoc.stylepp); // conjTablemodele.Espace (inbLignes) ;

        for (char c : (Conjugueur.M.ConjugGrecA.cbVerbeM.get(contrôleur.model.getIndVerbe()).getAttributeValue(Conjugueur.M.ConjugGrecA.ATTRIBUT)).substring(0, Conjugueur.M.ConjugGrecA.cbVerbeM.get(contrôleur.model.getIndVerbe()).getAttributeValue(Conjugueur.M.ConjugGrecA.ATTRIBUT).length()- 1).toCharArray()){
    //        if (Consonne(c)) {                                // le caractère courant est une consonne
      //          nbcons++ ;
                Copier (String.valueOf(c), DéclinaisonStyledDoc.stylera) ;
//                conjTablemodele.Copier (inbLignes, Character.toString(personne.accent(temps, mode, (short)(nbcons-1))), DéclinaisonStyledDoc.stylesu) ;
        }                                                    // pour ts les caractères
         if (!personne.spip(contrôleur.model.getMode(), contrôleur.model.getThème(), contrôleur.model.getVoix(), 0).isEmpty())  Suffixer (personne.spip(contrôleur.model.getMode(), contrôleur.model.getThème(), contrôleur.model.getVoix(), 0)) ;

     }


    private static void adjustJTableRowSizes(JTable jTable) {
        for (int row = 0; row < jTable.getRowCount(); row++) {
            int maxHeight = 0;
            for (int column = 0; column < jTable.getColumnCount(); column++) {
                TableCellRenderer cellRenderer = jTable.getCellRenderer(row, column);
                Object valueAt = jTable.getValueAt(row, column);
                Component tableCellRendererComponent = cellRenderer.getTableCellRendererComponent(jTable, valueAt, false, false, row, column);
                int heightPreferable = tableCellRendererComponent.getPreferredSize().height;
                maxHeight = Math.max(heightPreferable, maxHeight);
            }
            jTable.setRowHeight(row, maxHeight);
        }
    }
